mapper.update:
UPDATE jsh_freight_statement
SET status=#{status}, sign_status=#{signStatus}, attachment=#{attachment},
    remark=#{remark}, total_weight=#{totalWeight}, total_freight=#{totalFreight},
    paid_amount=#{paidAmount}, delete_flag=#{deleteFlag}
WHERE id=#{id}

mapper.sql:
FROM jsh_freight_head fh LEFT JOIN jsh_freight_carrier fc ON fc.id = fh.carrier_id WHERE fh.status = '1' AND ifnull(fh.delete_flag,'0') != '1' AND fh.id NOT IN ( SELECT fsi.freight_head_id FROM jsh_freight_statement_item fsi JOIN jsh_freight_statement fs ON fs.id = fsi.statement_id AND ifnull(fs.delete_flag,'0') != '1' WHERE ifnull(fsi.delete_flag,'0') != '1' )
AND fh.carrier_id = #{carrierId}
AND fh.bill_time >= #{beginTime}
AND fh.bill_time <= concat(#{endTime}, ' 23:59:59')

mapper.select:
SELECT fs.id, fs.statement_no as statementNo, fc.name as carrierName, DATE_FORMAT(fs.begin_time,'%Y-%m-%d') as beginTimeStr, DATE_FORMAT(fs.end_time,'%Y-%m-%d') as endTimeStr, fs.total_weight as totalWeight, fs.total_freight as totalFreight, ifnull(fs.paid_amount,0) as paidAmount, fs.status, fs.sign_status as signStatus, DATE_FORMAT(fs.create_time,'%Y-%m-%d %H:%i:%s') as createTimeStr, fs.remark, fs.attachment FROM jsh_freight_statement fs LEFT JOIN jsh_freight_carrier fc ON fc.id = fs.carrier_id WHERE ifnull(fs.delete_flag,'0') != '1'
AND fs.carrier_id = #{carrierId}
AND fs.status = #{status}
AND fs.sign_status = #{signStatus}
AND fs.begin_time >= #{beginTime}
AND fs.end_time <= concat(#{endTime}, ' 23:59:59')
ORDER BY fs.create_time DESC LIMIT #{offset}, #{rows}

SELECT count(1)
FROM jsh_freight_statement fs
WHERE ifnull(fs.delete_flag,'0') != '1'

  AND fs.carrier_id = #{carrierId}


  AND fs.status = #{status}


  AND fs.sign_status = #{signStatus}


  AND fs.begin_time >= #{beginTime}


  AND fs.end_time <= concat(#{endTime}, ' 23:59:59')
